  ('dietitian-moex-10954', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以下有關消瘦症（marasmus）的敘述，何者不正確？ 肌肉耗損，體重減輕    水腫、脂肪肝 為蛋白質與熱量之營養缺乏症  生長遲緩', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10955', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有計畫的行為改變之發展步驟中，下列那一階段已經可以將新習慣當成自己的習慣？ 知覺期  嘗試期  適應期  增強期', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10956', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在下列何種狀況下，諮詢最不易成功？ 諮詢過程中，被諮詢者有家人支持  諮詢過程中，被諮詢者有點焦慮自己的病情 每一次諮詢由不同營養師輪流負責  被諮詢者能主動參與諮詢過程', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10957', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '卜小姐平均每日吃300 g之蔬菜，請問她要如何才能符合行政院衛生署所訂定之每日飲食指南，有關蔬菜之建議？ 少攝取100 g  不用增減  多攝取100 g  多攝取200 g', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10958', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關營養諮詢，下列敘述何者錯誤？ 在一個舒適的環境中進行    諮詢者可用開放式的問題表達意見 讓被諮詢者有足夠的時間提出問題  諮詢者可用醫學術語溝通病情', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10959', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '近年來，台灣地區全國營養調查所使用之家戶食物盤存秤重法評估國人營養素攝取量時，在估計各家戶早、午、晚三 餐之進食單位之比率分別為： 1/3，1/3，1/3  1/5，2/5，2/5  1/7，3/7，3/7  1/4，3/8，3/8', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "d008ab3ebbd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10960', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據第三次全國營養調查結果，若以身體質量指數（BMI）大於26.4作為肥胖之切點，則台灣地區45歲以上成年女 性肥胖的比率約為： 10%  20%  30%  40%', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "d008ab3ebbd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10961', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '第三次全國營養調查（1993-96），台灣地區19-64歲男女，平均脂肪攝取量約佔總熱量之多少百分比率之間？ 25-30%  30-35%  35-40%  40-50%', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "d008ab3ebbd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10962', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何種評估方法最適合用來評估組織中營養素儲存量之減少？ 體位測量  生化檢驗  臨床症狀檢查  膳食調查', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "d008ab3ebbd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
